import 'package:baseball_detector_flutter/data/models/ai_coach/new_pitch.dart';
import 'package:baseball_detector_flutter/data/models/ball.dart';
import 'package:baseball_detector_flutter/data/models/dto/player/handedness.dart';
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/hooks/use_ai_coach_validation.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('validateAICoachInput', () {
    // テスト用のヘルパー関数
    Player createPlayer({
      Handedness pitchingHand = Handedness.right,
      DateTime? birthday,
    }) {
      return Player(
        id: 'test-player-id',
        name: 'Test Player',
        pitchingHand: pitchingHand,
        birthday: birthday,
      );
    }

    List<Ball> createPitchingBalls(int count, {bool withPitchTypes = true}) {
      return List.generate(
        count,
        (index) => Ball(
          id: 'ball-$index',
          pitchType: withPitchTypes
              ? NewPitch(
                  pitchType: 'fastball',
                  speed: 140.0 + index,
                )
              : null,
        ),
      );
    }

    group('投球データ数のバリデーション', () {
      test('10個未満の投球データの場合、notEnoughPitchingData を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(9);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.notEnoughPitchingData);
      });

      test('ちょうど10個の投球データの場合、次のバリデーションに進む', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, isNot(AICoachValidator.notEnoughPitchingData));
      });

      test('空の投球データの場合、notEnoughPitchingData を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = <Ball>[];

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.notEnoughPitchingData);
      });
    });

    group('球種タグのバリデーション', () {
      test('すべての投球に球種タグがある場合、次のバリデーションに進む', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(10, withPitchTypes: true);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, isNot(AICoachValidator.missingPitchTypes));
      });

      test('球種タグが null の投球がある場合、missingPitchTypes を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = [
          ...createPitchingBalls(9, withPitchTypes: true),
          Ball(id: 'ball-without-type', pitchType: null),
        ];

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.missingPitchTypes);
      });

      test('球種タイプが "none" の投球がある場合、missingPitchTypes を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = [
          ...createPitchingBalls(9, withPitchTypes: true),
          Ball(
            id: 'ball-with-none-type',
            pitchType: NewPitch(pitchType: 'none', speed: 0),
          ),
        ];

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.missingPitchTypes);
      });

      test('複数の投球に球種タグがない場合、missingPitchTypes を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = [
          ...createPitchingBalls(8, withPitchTypes: true),
          Ball(id: 'ball-1', pitchType: null),
          Ball(id: 'ball-2', pitchType: null),
        ];

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.missingPitchTypes);
      });
    });

    group('プレイヤー情報のバリデーション', () {
      test('プレイヤーが null の場合、missingPlayerInfo を返す', () {
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: null,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.missingPlayerInfo);
      });

      test('投球利き腕が none の場合、missingPlayerInfo を返す', () {
        final player = createPlayer(
          pitchingHand: Handedness.none,
          birthday: DateTime(2000, 1, 1),
        );
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.missingPlayerInfo);
      });

      test('誕生日が null の場合、missingPlayerInfo を返す', () {
        final player = createPlayer(
          pitchingHand: Handedness.right,
          birthday: null,
        );
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.missingPlayerInfo);
      });

      test('投球利き腕と誕生日の両方が欠けている場合、missingPlayerInfo を返す', () {
        final player = createPlayer(
          pitchingHand: Handedness.none,
          birthday: null,
        );
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.missingPlayerInfo);
      });

      test('投球利き腕が left で誕生日がある場合、次のバリデーションに進む', () {
        final player = createPlayer(
          pitchingHand: Handedness.left,
          birthday: DateTime(2000, 1, 1),
        );
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, isNot(AICoachValidator.missingPlayerInfo));
      });
    });

    group('利用回数上限のバリデーション', () {
      test('現在の利用回数が上限に達している場合、usageLimitReached を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 10,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.usageLimitReached);
      });

      test('現在の利用回数が上限を超えている場合、usageLimitReached を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 11,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.usageLimitReached);
      });

      test('現在の利用回数が上限未満の場合、ok を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 9,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.ok);
      });

      test('maxUsage が null の場合、利用回数チェックをスキップして ok を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 100,
          maxUsage: null,
        );

        expect(result, AICoachValidator.ok);
      });

      test('currentUsage が null の場合、利用回数チェックをスキップして ok を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: null,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.ok);
      });

      test('currentUsage と maxUsage が両方 null の場合、利用回数チェックをスキップして ok を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: null,
          maxUsage: null,
        );

        expect(result, AICoachValidator.ok);
      });
    });

    group('統合テスト - すべての条件を満たす場合', () {
      test('すべてのバリデーションを通過した場合、ok を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(15);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 5,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.ok);
      });

      test('最小限の条件（10個の投球、利き腕と誕生日あり、利用上限なし）で ok を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: null,
          maxUsage: null,
        );

        expect(result, AICoachValidator.ok);
      });
    });
  });
}

