/// {@category Data}
library;

// Package imports:
import 'package:freezed_annotation/freezed_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';
import 'package:baseball_detector_flutter/data/models/pitch_type.dart';
import 'package:baseball_detector_flutter/data/models/utils/json_big_int_converter.dart';

part 'ball.freezed.dart';
part 'ball.g.dart';

@freezed
abstract class Ball with _$Ball {
  @JsonSerializable(
      explicitToJson: true, fieldRename: Constants.modelFieldRename)
  const factory Ball({
    @Default(null) @JsonBigIntConverter() int? id,
    @Default(null) @JsonBigIntConverter() int? ballIndex,
    @Default(null) DateTime? createdAt, // assumes UTC
    @Default(null) DateTime? updatedAt, // assumes UTC
    @Default(null) PitchType? pitchType,
    @Default(null) String? pitchTypeId,
    @Default(null) String? resourceId,
    @Default(null) bool? isHit,
    @Default(null) bool? isPitched,
    @Default(null) double? activeSpin,
    @Default(null) double? angle,
    @Default(null) double? efficiency,
    @Default(null) double? exitVelocity,
    @Default(null) double? foundAt,
    @Default(null) double? gyroDegree,
    @Default(null) double? horizontalBreak,
    @Default(null) double? initialVelocity,
    @Default(null) double? spinDirection,
    @Default(null) double? totalSpin,
    @Default(null) double? verticalBreak,
    @Default(null) String? presignedAnnotatedVideoUrl,
    @Default(null) String? presignedExtractedVideoUrl,
  }) = _Ball;

  factory Ball.fromJson(Map<String, dynamic> json) => _$BallFromJson(json);
}

/// {@category Data}
library;

// Project imports:
import 'package:baseball_detector_flutter/data/models/dto/player/handedness.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_domain.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_level.dart';
import 'package:baseball_detector_flutter/data/models/user_info.dart';

class Player {
  final String? id;
  final String? userId;
  final String? teamId;
  final String? name;
  final String? note;
  final DateTime? createdAt; // assumes UTC
  final bool? deleteFlag;
  final DateTime? updatedAt; // assumes UTC
  final String? imageUrl;
  final String? presignedImageUrl;
  final Handedness pitchingHand;
  final Handedness hittingHand;
  final DateTime? birthday;

  const Player({
