          : Handedness.values.firstWhere((e) => e.name == json['stand'],
              orElse: () => Handedness.none),
      birthday: json['birthday'] == null
          ? null
          : DateTime.parse(json['birthday'] as String),
    );
  }

  Map<String, dynamic> toJson() {
