@freezed
abstract class Proposal with _$Proposal {
  @JsonSerializable(
    explicitToJson: true,
    fieldRename: FieldRename.none,
  )
  const factory Proposal({
    required PitchType pitchType,
    required List<String> reasons,
    required TargetSpecs targetSpecs,
    required List<String> expectedEffects,
  }) = _Proposal;

  factory Proposal.fromJson(Map<String, dynamic> json) =>
      _$ProposalFromJson(json);
}

@freezed
abstract class TargetSpecs with _$TargetSpecs {
  @JsonSerializable(
    explicitToJson: true,
    fieldRename: FieldRename.none,
  )
  const factory TargetSpecs({
    required List<num> initialVelocity,
    required List<num> verticalBreak,
    required List<num> horizontalBreak,
  }) = _TargetSpecs;

  factory TargetSpecs.fromJson(Map<String, dynamic> json) =>
      _$TargetSpecsFromJson(json);
}

