/// {@category Data}
library;

// Package imports:
import 'package:freezed_annotation/freezed_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';

part 'pitch_type.freezed.dart';
part 'pitch_type.g.dart';

@freezed
abstract class PitchType with _$PitchType {
  @JsonSerializable(
      explicitToJson: true, fieldRename: Constants.modelFieldRename)
  const factory PitchType({
    @Default(null) String? id,
    @Default(null) String? pitchType,
    @Default(null) int? priority,
    @Default(null) String? groupingTag,
    @Default(null) DateTime? createdAt, // assumes UTC
    @Default(null) DateTime? updatedAt, // assumes UTC
    @Default(null) bool? deleteFlag,
  }) = _PitchType;

  factory PitchType.fromJson(Map<String, dynamic> json) =>
      _$PitchTypeFromJson(json);
}

